Javascript.initialise:
var eventNode = WP.GetScreenProcess().getRequest().getContext().selectSingleNode("WordProcessing/Event/StandardEventId");
eventid = (null != eventNode) ? XML.getNodeTextContent(eventNode) : "";
if (450 == eventid) {
	Services.setValue(IsN39Reqd.dataBinding, "Y"); }
else {
	Services.setValue(IsN39Reqd.dataBinding, "N"); }
